async (page) => {
  const result = await page.evaluate(({x, y}) => JSON.stringify(window.__navigateTo(x, y)), {x: 270, y: 130});
  await page.waitForTimeout(15000);
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({
      pos: gs.player_position,
      nav: gs.navigation?.status,
      nearby: gs.nearby_entities.slice(0, 10).map(e => e.name + '(' + e.x + ',' + e.y + ')')
    });
  });
  return state;
}

async (page) => {
  const result = await page.evaluate(() => JSON.stringify(window.__interactNPC('Dying Soldier')));
  await page.waitForTimeout(2000);
  return result;
}

async (page) => {
  const burgerSlot = await page.evaluate(() => window.__latestGameState.inventory.find(i => i.name === 'Burger')?.slot);
  if (burgerSlot !== undefined) {
    await page.evaluate(s => window.game.menu.getInventory().selectEdible(s), burgerSlot);
    await page.waitForTimeout(500);
    await page.evaluate(s => window.game.menu.getInventory().selectEdible(s), burgerSlot);
  }
  await page.waitForTimeout(25000);
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return { pos: gs.player_position, nav: gs.navigation?.status, wp: gs.navigation?.current_wp + '/' + gs.navigation?.total_wps, hp: gs.player_stats.hp + '/' + gs.player_stats.max_hp, burgers: gs.inventory.find(i=>i.name==='Burger')?.count || 0 };
  });
  return JSON.stringify(state);
}

async (page) => {
  await page.waitForTimeout(20000);
  const gs = await page.evaluate(() => window.__latestGameState);
  const hp = gs.player_stats.hp, maxHp = gs.player_stats.max_hp;

  // Heal if below 60%
  if (hp < maxHp * 0.6) {
    const slot = gs.inventory.find(i => i.name === 'Big Flask' || i.name === 'Burger')?.slot;
    if (slot !== undefined) {
      await page.evaluate(s => window.game.menu.getInventory().selectEdible(s), slot);
      await page.waitForTimeout(500);
    }
  }

  return JSON.stringify({ pos: gs.player_position, nav: gs.navigation?.status, wp: (gs.navigation?.current_wp||0) + '/' + (gs.navigation?.total_wps||0), hp: hp + '/' + maxHp });
}

async (page) => {
  await page.waitForTimeout(30000);
  const gs = await page.evaluate(() => window.__latestGameState);
  const hp = gs.player_stats.hp, maxHp = gs.player_stats.max_hp;

  if (hp < maxHp * 0.5) {
    const slot = gs.inventory.find(i => i.name === 'Big Flask' || i.name === 'Burger' || i.name === 'Blueberry')?.slot;
    if (slot !== undefined) await page.evaluate(s => window.game.menu.getInventory().selectEdible(s), slot);
  }

  return JSON.stringify({ pos: gs.player_position, nav: gs.navigation?.status, wp: (gs.navigation?.current_wp||0) + '/' + (gs.navigation?.total_wps||0), hp: hp + '/' + maxHp, level: gs.player_stats.level });
}

async (page) => {
  await page.waitForTimeout(20000);
  const gs = await page.evaluate(() => window.__latestGameState);
  const hp = gs.player_stats.hp, maxHp = gs.player_stats.max_hp;

  if (hp < maxHp * 0.5) {
    const slot = gs.inventory.find(i => i.name === 'Big Flask' || i.name === 'Blueberry')?.slot;
    if (slot !== undefined) await page.evaluate(s => window.game.menu.getInventory().selectEdible(s), slot);
  }

  const npcs = gs.nearby_entities.filter(e => e.type === 1).slice(0,5).map(e => e.name + '@(' + e.x + ',' + e.y + ')d=' + e.distance);
  return JSON.stringify({ pos: gs.player_position, nav: gs.navigation?.status, hp: hp + '/' + maxHp, npcs });
}

